__host__ __device__ inline float
createRoundingFactor(float max, int n) {
  float delta = (max * (float)n) / (1.f - 2.f * (float)n * FLT_EPSILON);









  int exp;
  frexpf(delta, &exp);



  return ldexpf(1.f, exp);
}

