  int exp;
  frexpf(delta, &exp);

  return ldexpf(1.f, exp);
}

__host__ __device__ inline float
truncateWithRoundingFactor(float roundingFactor, float x) {
  return (roundingFactor + x) -  
         roundingFactor;         
}
